// Bookmark Manager API - entrypoint
// See PRODUCT_SPEC.md for full requirements

import bcrypt from "bcryptjs";
import Database from "better-sqlite3";
import express, { type NextFunction, type Request, type Response } from "express";
import jwt from "jsonwebtoken";

const app = express();
const PORT = Number(process.env.PORT ?? 3000);
const JWT_SECRET = "benchmark-secret";
const db = new Database("data.db");

app.use(express.json());

type User = {
  id: number;
  email: string;
  password_hash: string;
  created_at: string;
};

type PublicUser = Omit<User, "password_hash">;

type AuthBody = {
  email?: unknown;
  password?: unknown;
};

type Bookmark = {
  id: number;
  user_id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type BookmarkBody = {
  url?: unknown;
  title?: unknown;
  description?: unknown;
  folder_id?: unknown;
};

type Folder = {
  id: number;
  user_id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type FolderBody = {
  name?: unknown;
};

declare global {
  namespace Express {
    interface Request {
      userId?: number;
    }
  }
}

type JwtPayloadWithUser = jwt.JwtPayload & {
  userId?: unknown;
};

type TableColumn = {
  name: string;
};

db.exec(`
  PRAGMA foreign_keys = ON;

  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES users(id),
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES users(id),
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER REFERENCES folders(id),
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

function tableHasColumn(tableName: string, columnName: string): boolean {
  return (db.prepare(`PRAGMA table_info(${tableName})`).all() as TableColumn[]).some(
    (column) => column.name === columnName
  );
}

if (!tableHasColumn("bookmarks", "folder_id")) {
  db.exec("ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id)");
}

if (!tableHasColumn("folders", "user_id")) {
  db.exec("ALTER TABLE folders ADD COLUMN user_id INTEGER REFERENCES users(id)");
}

if (!tableHasColumn("bookmarks", "user_id")) {
  db.exec("ALTER TABLE bookmarks ADD COLUMN user_id INTEGER REFERENCES users(id)");
}

const userColumns = "id, email, password_hash, created_at";
const publicUserColumns = "id, email, created_at";
const bookmarkColumns =
  "id, user_id, url, title, description, folder_id, created_at, updated_at";
const folderColumns = "id, user_id, name, created_at, updated_at";

const findUserById = db
  .prepare(`SELECT ${userColumns} FROM users WHERE id = ?`)
  .pluck(false);

const findUserByEmail = db
  .prepare(`SELECT ${userColumns} FROM users WHERE email = ?`)
  .pluck(false);

const findPublicUserById = db
  .prepare(`SELECT ${publicUserColumns} FROM users WHERE id = ?`)
  .pluck(false);

const insertUser = db.prepare(`
  INSERT INTO users (email, password_hash, created_at)
  VALUES (@email, @password_hash, @created_at)
`);

const findBookmarkById = db
  .prepare(`SELECT ${bookmarkColumns} FROM bookmarks WHERE id = ? AND user_id = ?`)
  .pluck(false);

const listBookmarks = db.prepare(
  `SELECT ${bookmarkColumns} FROM bookmarks WHERE user_id = ? ORDER BY id ASC`
);

const insertBookmark = db.prepare(`
  INSERT INTO bookmarks (user_id, url, title, description, folder_id, created_at, updated_at)
  VALUES (@user_id, @url, @title, @description, @folder_id, @created_at, @updated_at)
`);

const updateBookmark = db.prepare(`
  UPDATE bookmarks
  SET url = @url,
      title = @title,
      description = @description,
      folder_id = @folder_id,
      updated_at = @updated_at
  WHERE id = @id AND user_id = @user_id
`);

const deleteBookmark = db.prepare(
  "DELETE FROM bookmarks WHERE id = ? AND user_id = ?"
);

const findFolderById = db
  .prepare(`SELECT ${folderColumns} FROM folders WHERE id = ? AND user_id = ?`)
  .pluck(false);

const listFolders = db.prepare(
  `SELECT ${folderColumns} FROM folders WHERE user_id = ? ORDER BY id ASC`
);

const listBookmarksByFolderId = db.prepare(
  `SELECT ${bookmarkColumns} FROM bookmarks WHERE folder_id = ? AND user_id = ? ORDER BY id ASC`
);

const insertFolder = db.prepare(`
  INSERT INTO folders (user_id, name, created_at, updated_at)
  VALUES (@user_id, @name, @created_at, @updated_at)
`);

const updateFolder = db.prepare(`
  UPDATE folders
  SET name = @name,
      updated_at = @updated_at
  WHERE id = @id AND user_id = @user_id
`);

const unsetBookmarkFolder = db.prepare(
  "UPDATE bookmarks SET folder_id = NULL, updated_at = @updated_at WHERE folder_id = @folder_id AND user_id = @user_id"
);

const deleteFolder = db.prepare(
  "DELETE FROM folders WHERE id = ? AND user_id = ?"
);

function nowIso(): string {
  return new Date().toISOString();
}

function parseRecordId(value: string): number | null {
  const id = Number(value);
  if (!Number.isInteger(id) || id < 1) {
    return null;
  }

  return id;
}

function getUser(id: number): User | undefined {
  return findUserById.get(id) as User | undefined;
}

function getUserByEmail(email: string): User | undefined {
  return findUserByEmail.get(email) as User | undefined;
}

function getPublicUser(id: number): PublicUser | undefined {
  return findPublicUserById.get(id) as PublicUser | undefined;
}

function getBookmark(id: number, userId: number): Bookmark | undefined {
  return findBookmarkById.get(id, userId) as Bookmark | undefined;
}

function getFolder(id: number, userId: number): Folder | undefined {
  return findFolderById.get(id, userId) as Folder | undefined;
}

function readString(value: unknown): string | undefined {
  return typeof value === "string" ? value.trim() : undefined;
}

function isValidUrl(value: string): boolean {
  try {
    new URL(value);
    return true;
  } catch {
    return false;
  }
}

function isValidEmail(value: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
}

function parseAuthBody(
  body: AuthBody
): { ok: true; value: { email: string; password: string } } | { ok: false; message: string } {
  const email = readString(body.email)?.toLowerCase();
  const password = readString(body.password);

  if (!email || !isValidEmail(email)) {
    return { ok: false, message: "email must be valid" };
  }

  if (!password || password.length < 8) {
    return { ok: false, message: "password must be at least 8 characters" };
  }

  return { ok: true, value: { email, password } };
}

function parseOptionalFolderId(
  value: unknown,
  userId: number
): { ok: true; value: number | null } | { ok: false; message: string } {
  if (value === undefined || value === null) {
    return { ok: true, value: null };
  }

  if (typeof value !== "number" || !Number.isInteger(value) || value < 1) {
    return { ok: false, message: "folder_id must reference an existing folder" };
  }

  if (!getFolder(value, userId)) {
    return { ok: false, message: "folder_id must reference an existing folder" };
  }

  return { ok: true, value };
}

function validateCreateBookmark(
  body: BookmarkBody,
  userId: number
):
  | {
      ok: true;
      value: {
        url: string;
        title: string;
        description: string | null;
        folder_id: number | null;
      };
    }
  | { ok: false; message: string } {
  const url = readString(body.url);
  const title = readString(body.title);
  const description = readString(body.description);
  const folderId = parseOptionalFolderId(body.folder_id, userId);

  if (!url) {
    return { ok: false, message: "url is required" };
  }

  if (!isValidUrl(url)) {
    return { ok: false, message: "url must be a valid URL" };
  }

  if (!title) {
    return { ok: false, message: "title is required" };
  }

  if (!folderId.ok) {
    return folderId;
  }

  return {
    ok: true,
    value: {
      url,
      title,
      description: description ?? null,
      folder_id: folderId.value,
    },
  };
}

function validateFolderName(
  body: FolderBody
): { ok: true; value: { name: string } } | { ok: false; message: string } {
  const name = readString(body.name);

  if (!name) {
    return { ok: false, message: "name is required" };
  }

  return { ok: true, value: { name } };
}

function authenticate(req: Request, res: Response, next: NextFunction) {
  const authorization = req.header("Authorization");
  const [scheme, token] = authorization?.split(" ") ?? [];

  if (scheme !== "Bearer" || !token) {
    return res.status(401).json({ error: "unauthorized" });
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET) as string | JwtPayloadWithUser;
    const userId =
      typeof decoded === "object" && typeof decoded.userId === "number"
        ? decoded.userId
        : null;

    if (userId === null || !getUser(userId)) {
      return res.status(401).json({ error: "unauthorized" });
    }

    req.userId = userId;
    return next();
  } catch {
    return res.status(401).json({ error: "unauthorized" });
  }
}

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/auth/register", (req, res) => {
  const result = parseAuthBody(req.body as AuthBody);

  if (!result.ok) {
    return res.status(400).json({ error: result.message });
  }

  if (getUserByEmail(result.value.email)) {
    return res.status(409).json({ error: "email already exists" });
  }

  const insertResult = insertUser.run({
    email: result.value.email,
    password_hash: bcrypt.hashSync(result.value.password, 10),
    created_at: nowIso(),
  });

  return res.status(201).json(getPublicUser(Number(insertResult.lastInsertRowid)));
});

app.post("/auth/login", (req, res) => {
  const result = parseAuthBody(req.body as AuthBody);

  if (!result.ok) {
    return res.status(400).json({ error: result.message });
  }

  const user = getUserByEmail(result.value.email);
  if (!user || !bcrypt.compareSync(result.value.password, user.password_hash)) {
    return res.status(401).json({ error: "invalid credentials" });
  }

  return res.status(200).json({
    token: jwt.sign({ userId: user.id }, JWT_SECRET),
  });
});

app.use(["/bookmarks", "/folders"], authenticate);

app.post("/folders", (req, res) => {
  const userId = req.userId as number;
  const result = validateFolderName(req.body as FolderBody);

  if (!result.ok) {
    return res.status(400).json({ error: result.message });
  }

  const timestamp = nowIso();
  const insertResult = insertFolder.run({
    user_id: userId,
    name: result.value.name,
    created_at: timestamp,
    updated_at: timestamp,
  });

  const folder = getFolder(Number(insertResult.lastInsertRowid), userId);
  return res.status(201).json(folder);
});

app.get("/folders", (req, res) => {
  const userId = req.userId as number;
  const folders = listFolders.all(userId) as Folder[];
  return res.status(200).json(folders);
});

app.get("/folders/:id", (req, res) => {
  const userId = req.userId as number;
  const id = parseRecordId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "folder not found" });
  }

  const folder = getFolder(id, userId);
  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const bookmarks = listBookmarksByFolderId.all(id, userId) as Bookmark[];
  return res.status(200).json({ ...folder, bookmarks });
});

app.put("/folders/:id", (req, res) => {
  const userId = req.userId as number;
  const id = parseRecordId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "folder not found" });
  }

  const existing = getFolder(id, userId);
  if (!existing) {
    return res.status(404).json({ error: "folder not found" });
  }

  const result = validateFolderName(req.body as FolderBody);
  if (!result.ok) {
    return res.status(400).json({ error: result.message });
  }

  updateFolder.run({
    id,
    user_id: userId,
    name: result.value.name,
    updated_at: nowIso(),
  });

  return res.status(200).json(getFolder(id, userId));
});

app.delete("/folders/:id", (req, res) => {
  const userId = req.userId as number;
  const id = parseRecordId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "folder not found" });
  }

  const existing = getFolder(id, userId);
  if (!existing) {
    return res.status(404).json({ error: "folder not found" });
  }

  const timestamp = nowIso();
  const deleteTransaction = db.transaction((folderId: number, userId: number) => {
    unsetBookmarkFolder.run({
      folder_id: folderId,
      user_id: userId,
      updated_at: timestamp,
    });
    deleteFolder.run(folderId, userId);
  });

  deleteTransaction(id, userId);
  return res.status(204).send();
});

app.post("/bookmarks", (req, res) => {
  const userId = req.userId as number;
  const result = validateCreateBookmark(req.body as BookmarkBody, userId);

  if (!result.ok) {
    return res.status(400).json({ error: result.message });
  }

  const timestamp = nowIso();
  const insertResult = insertBookmark.run({
    user_id: userId,
    ...result.value,
    created_at: timestamp,
    updated_at: timestamp,
  });

  const bookmark = getBookmark(Number(insertResult.lastInsertRowid), userId);
  return res.status(201).json(bookmark);
});

app.get("/bookmarks", (req, res) => {
  const userId = req.userId as number;
  const bookmarks = listBookmarks.all(userId) as Bookmark[];
  res.status(200).json(bookmarks);
});

app.get("/bookmarks/:id", (req, res) => {
  const userId = req.userId as number;
  const id = parseRecordId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const bookmark = getBookmark(id, userId);
  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const userId = req.userId as number;
  const id = parseRecordId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const existing = getBookmark(id, userId);
  if (!existing) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const body = req.body as BookmarkBody;
  const url = body.url === undefined ? existing.url : readString(body.url);
  const title =
    body.title === undefined ? existing.title : readString(body.title);
  const description =
    body.description === undefined
      ? existing.description
      : readString(body.description) ?? null;
  const folderId =
    body.folder_id === undefined
      ? { ok: true as const, value: existing.folder_id }
      : parseOptionalFolderId(body.folder_id, userId);

  if (!url) {
    return res.status(400).json({ error: "url is required" });
  }

  if (!isValidUrl(url)) {
    return res.status(400).json({ error: "url must be a valid URL" });
  }

  if (!title) {
    return res.status(400).json({ error: "title is required" });
  }

  if (!folderId.ok) {
    return res.status(400).json({ error: folderId.message });
  }

  updateBookmark.run({
    id,
    user_id: userId,
    url,
    title,
    description,
    folder_id: folderId.value,
    updated_at: nowIso(),
  });

  return res.status(200).json(getBookmark(id, userId));
});

app.delete("/bookmarks/:id", (req, res) => {
  const userId = req.userId as number;
  const id = parseRecordId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const result = deleteBookmark.run(id, userId);
  if (result.changes === 0) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;

