// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";
import bcrypt from "bcryptjs";
import jwt from "jsonwebtoken";
import type { NextFunction, Request, Response } from "express";

const app = express();
const PORT = Number(process.env.PORT) || 3000;
const db = new Database("data.db");
const JWT_SECRET = "benchmark-secret";

type JwtPayload = {
  userId: number;
};

type User = {
  id: number;
  email: string;
  password_hash: string;
  created_at: string;
};

type PublicUser = Omit<User, "password_hash">;

type Bookmark = {
  id: number;
  user_id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  user_id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type FolderWithBookmarks = Folder & {
  bookmarks: Bookmark[];
};

app.use(express.json());

db.pragma("foreign_keys = ON");

db.exec(`
  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
    FOREIGN KEY (folder_id) REFERENCES folders(id) ON DELETE SET NULL
  )
`);

const folderColumns = db.prepare("PRAGMA table_info(folders)").all() as Array<{ name: string }>;
if (!folderColumns.some((column) => column.name === "user_id")) {
  db.prepare("ALTER TABLE folders ADD COLUMN user_id INTEGER REFERENCES users(id) ON DELETE CASCADE").run();
}

const bookmarkColumns = db.prepare("PRAGMA table_info(bookmarks)").all() as Array<{ name: string }>;
if (!bookmarkColumns.some((column) => column.name === "folder_id")) {
  db.prepare("ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL").run();
}
if (!bookmarkColumns.some((column) => column.name === "user_id")) {
  db.prepare("ALTER TABLE bookmarks ADD COLUMN user_id INTEGER REFERENCES users(id) ON DELETE CASCADE").run();
}

const toPublicUser = (user: User): PublicUser => ({
  id: user.id,
  email: user.email,
  created_at: user.created_at,
});

const getUserByEmail = (email: string): User | undefined => {
  return db.prepare("SELECT id, email, password_hash, created_at FROM users WHERE email = ?").get(email) as
    | User
    | undefined;
