// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";

const app = express();
const PORT = Number(process.env.PORT ?? 3000);
const db = new Database("data.db");

app.use(express.json());

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  created_at: string;
  updated_at: string;
};

type BookmarkBody = {
  url?: unknown;
  title?: unknown;
  description?: unknown;
};

db.exec(`
  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

const bookmarkColumns = "id, url, title, description, created_at, updated_at";

const findBookmarkById = db
  .prepare(`SELECT ${bookmarkColumns} FROM bookmarks WHERE id = ?`)
  .pluck(false);

const listBookmarks = db.prepare(
  `SELECT ${bookmarkColumns} FROM bookmarks ORDER BY id ASC`
);

const insertBookmark = db.prepare(`
  INSERT INTO bookmarks (url, title, description, created_at, updated_at)
  VALUES (@url, @title, @description, @created_at, @updated_at)
`);

const updateBookmark = db.prepare(`
  UPDATE bookmarks
  SET url = @url,
      title = @title,
      description = @description,
      updated_at = @updated_at
  WHERE id = @id
`);

const deleteBookmark = db.prepare("DELETE FROM bookmarks WHERE id = ?");

function nowIso(): string {
  return new Date().toISOString();
}

function parseBookmarkId(value: string): number | null {
  const id = Number(value);
  if (!Number.isInteger(id) || id < 1) {
    return null;
  }

  return id;
}

function getBookmark(id: number): Bookmark | undefined {
  return findBookmarkById.get(id) as Bookmark | undefined;
}

function readString(value: unknown): string | undefined {
  return typeof value === "string" ? value.trim() : undefined;
}

function isValidUrl(value: string): boolean {
  try {
    new URL(value);
    return true;
  } catch {
    return false;
  }
}

function validateCreateBookmark(body: BookmarkBody):
  | { ok: true; value: { url: string; title: string; description: string | null } }
  | { ok: false; message: string } {
  const url = readString(body.url);
  const title = readString(body.title);
  const description = readString(body.description);

  if (!url) {
    return { ok: false, message: "url is required" };
  }

  if (!isValidUrl(url)) {
    return { ok: false, message: "url must be a valid URL" };
  }

  if (!title) {
    return { ok: false, message: "title is required" };
  }

  return {
    ok: true,
    value: {
      url,
      title,
      description: description ?? null,
    },
  };
}

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/bookmarks", (req, res) => {
  const result = validateCreateBookmark(req.body as BookmarkBody);

  if (!result.ok) {
    return res.status(400).json({ error: result.message });
  }

  const timestamp = nowIso();
  const insertResult = insertBookmark.run({
    ...result.value,
    created_at: timestamp,
    updated_at: timestamp,
  });

  const bookmark = getBookmark(Number(insertResult.lastInsertRowid));
  return res.status(201).json(bookmark);
});

app.get("/bookmarks", (_req, res) => {
  const bookmarks = listBookmarks.all() as Bookmark[];
  res.status(200).json(bookmarks);
});

app.get("/bookmarks/:id", (req, res) => {
  const id = parseBookmarkId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const bookmark = getBookmark(id);
  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const id = parseBookmarkId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const existing = getBookmark(id);
  if (!existing) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const body = req.body as BookmarkBody;
  const url = body.url === undefined ? existing.url : readString(body.url);
  const title =
    body.title === undefined ? existing.title : readString(body.title);
  const description =
    body.description === undefined
      ? existing.description
      : readString(body.description) ?? null;

  if (!url) {
    return res.status(400).json({ error: "url is required" });
  }

  if (!isValidUrl(url)) {
    return res.status(400).json({ error: "url must be a valid URL" });
  }

  if (!title) {
    return res.status(400).json({ error: "title is required" });
  }

  updateBookmark.run({
    id,
    url,
    title,
    description,
    updated_at: nowIso(),
  });

  return res.status(200).json(getBookmark(id));
});

app.delete("/bookmarks/:id", (req, res) => {
  const id = parseBookmarkId(req.params.id);

  if (id === null) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const result = deleteBookmark.run(id);
  if (result.changes === 0) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;
