  [ -f "$DB_PATH" ] || die "Database not found at $DB_PATH. Run: harness init"
}

sql_escape() { printf '%s' "$1" | sed "s/'/''/g"; }

sql_literal() { printf "'%s'" "$(sql_escape "$1")"; }

