  esac
}

normalize_lane() {
  local token
  token="$(normalize_token "$1")"
  case "$token" in
    tiny|normal|high_risk)
      printf '%s' "$token"
      ;;
    *)
      die "unknown lane '$1'. Use: tiny, normal, or high-risk"
      ;;
  esac
}

normalize_risk() {
  [ -z "$1" ] && return
  normalize_lane "$1"
}

require_integer() {
  local label="$1" value="$2"
  [[ "$value" =~ ^[0-9]+$ ]] || die "$label must be an integer"
}

require_bool() {
  local label="$1" value="$2"
  [[ "$value" =~ ^[01]$ ]] || die "$label must be 0 or 1"
}

json_array() {
  # Turn a comma-separated string into a JSON array.
  local input="$1"
  [ -z "$input" ] && printf 'null' && return
  printf '[%s]' "$(echo "$input" | sed 's/[[:space:]]*,[[:space:]]*/","/g; s/^/"/; s/$/"/')"
}

json_sql_value() {
  local input="$1"
  [ -z "$input" ] && printf 'NULL' && return
  printf "'%s'" "$(sql_escape "$(json_array "$input")")"
