./benchmark/runs/baseline-main-20260526/T3-folder-support/events.jsonl:28:{"type":"item.completed","item":{"id":"item_12","type":"command_execution","command":"/bin/zsh -lc "sed -n '1,320p' src/bookmarks.ts"","aggregated_output":"import { Router } from "express";
import { getDb } from "./database";

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  created_at: string;
  updated_at: string;
};

type BookmarkInput = {
  url?: unknown;
  title?: unknown;
  description?: unknown;
};

const router = Router();
const db = getDb();

const findBookmark = db
  .prepare("SELECT id, url, title, description, created_at, updated_at FROM bookmarks WHERE id = ?")
  .pluck(false);

const listBookmarks = db.prepare(
  "SELECT id, url, title, description, created_at, updated_at FROM bookmarks ORDER BY id ASC",
);

const insertBookmark = db.prepare(`
  INSERT INTO bookmarks (url, title, description, created_at, updated_at)
  VALUES (@url, @title, @description, @created_at, @updated_at)
`);

const updateBookmark = db.prepare(`
  UPDATE bookmarks
  SET url = @url,
      title = @title,
      description = @description,
      updated_at = @updated_at
  WHERE id = @id
`);

const deleteBookmark = db.prepare("DELETE FROM bookmarks WHERE id = ?");

function getBookmark(id: number): Bookmark | undefined {
  return findBookmark.get(id) as Bookmark | undefined;
}

function parseId(value: string): number | undefined {
  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : undefined;
}

function textField(value: unknown): string | undefined {
  return typeof value === "string" ? value.trim() : undefined;
}

function parseDescription(value: unknown): string | null {
  if (value === undefined || value === null) {
    return null;
  }

  return typeof value === "string" ? value : String(value);
}

function validateRequiredBookmark(input: BookmarkInput): { url: string; title: string; description: string | null } | { error: string } {
  const url = textField(input.url);
  const title = textField(input.title);

  if (!url) {
    return { error: "url is required" };
  }

  if (!title) {
    return { error: "title is required" };
  }

  return {
    url,
    title,
    description: parseDescription(input.description),
  };
}

router.post("/", (req, res) => {
  const parsed = validateRequiredBookmark(req.body as BookmarkInput);

  if ("error" in parsed) {
    res.status(400).json({ error: parsed.error });
    return;
  }

  const now = new Date().toISOString();
  const result = insertBookmark.run({
    url: parsed.url,
    title: parsed.title,
    description: parsed.description,
    created_at: now,
    updated_at: now,
  });

  const bookmark = getBookmark(Number(result.lastInsertRowid));
  res.status(201).json(bookmark);
});

router.get("/", (_req, res) => {
  res.status(200).json(listBookmarks.all() as Bookmark[]);
});

router.get("/:id", (req, res) => {
  const id = parseId(req.params.id);
  const bookmark = id ? getBookmark(id) : undefined;

  if (!bookmark) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  res.status(200).json(bookmark);
});

router.put("/:id", (req, res) => {
  const id = parseId(req.params.id);
  const current = id ? getBookmark(id) : undefined;

  if (!id || !current) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  const input = req.body as BookmarkInput;
  const url = input.url === undefined ? current.url : textField(input.url);
  const title = input.title === undefined ? current.title : textField(input.title);

  if (!url) {
    res.status(400).json({ error: "url is required" });
    return;
  }

  if (!title) {
    res.status(400).json({ error: "title is required" });
    return;
  }

  updateBookmark.run({
    id,
    url,
    title,
    description: input.description === undefined ? current.description : parseDescription(input.description),
    updated_at: new Date().toISOString(),
  });

  res.status(200).json(getBookmark(id));
});

router.delete("/:id", (req, res) => {
  const id = parseId(req.params.id);
  const result = id ? deleteBookmark.run(id) : { changes: 0 };

  if (result.changes === 0) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  res.status(204).send();
});

export default router;
