 17	async function request(path: string, init: RequestInit = {}) {
 18	  const headers = new Headers(init.headers);
 19	  if (init.body && !headers.has("Content-Type")) {
 20	    headers.set("Content-Type", "application/json");
 21	  }
 22	
 23	  return fetch(`${baseUrl}${path}`, {
 24	    ...init,
 25	    headers,
 26	  });
 27	}
